import { FC, useEffect, useState } from 'react';
import { Button, Result } from 'antd';
import { useSptTranslation } from '@spotter/i18n-sdk';
import React from 'react';
import { domBreakingAutoReporting } from '@spotter/app-client-toolkit';

export interface ClientErrorProps {
    error?: Error;
}

/**
 * 客户端错误
 * @param param0
 * @returns
 */

export const ClientError: FC<ClientErrorProps> = ({ error }) => {
    const [openDetail, setOpenDetail] = useState<boolean>(false);
    const { t } = useSptTranslation();
    useEffect(() => {
        domBreakingAutoReporting(new Error(error?.message));
    }, []);
    return (
        <div className="h-full">
            <div className="overflow-auto h-full flex flex-col box-border justify-between bg-white">
                <Result
                    title={t('infra.downgrade_client_crashed_title') as string}
                    subTitle={
                        openDetail ? (
                            <div>
                                <span className="mr-8px"> {error?.message}</span>
                            </div>
                        ) : (
                            <a
                                onClick={() => {
                                    setOpenDetail(true);
                                }}
                            >
                                {t('common.detail') as string}
                            </a>
                        )
                    }
                    status="500"
                    extra={
                        <Button type="primary" href="/">
                            {t('infra.back_home') as string}
                        </Button>
                    }
                />
            </div>
        </div>
    );
};
